t_id_fkey\" FOREIGN KEY (parent_id) REFERENCES test_table(id) ON UPDATE CASCADE ON DELETE CASCADE\n    TABLE \"test_schema\".\"cross_ref_child\" CONSTRAINT \"cross_ref_child_parent_id_fkey\" FOREIGN KEY (parent_id) REFERENCES test_table(id)\nTriggers:\n    test_trigger BEFORE UPDATE ON test_table FOR EACH ROW EXECUTE PROCEDURE trig_test()\n    test_trigger_after_delete AFTER DELETE ON test_table FOR EACH ROW EXECUTE PROCEDURE trig_test()\n    test_trigger_after_insert AFTER INSERT ON test_table FOR EACH ROW EXECUTE PROCEDURE trig_test()\n    test_trigger_statement AFTER INSERT ON test_table FOR EACH STATEMENT EXECUTE PROCEDURE trig_statement()\n    test_trigger_truncate AFTER TRUNCATE ON test_table FOR EACH STATEMENT EXECUTE PROCEDURE trig_statement() [disabled]\n    test_trigger_update_of BEFORE UPDATE OF email, status ON test_table FOR EACH ROW EXECUTE PROCEDURE trig_test()\n    test_trigger_when BEFORE UPDATE ON test_table FOR EACH ROW WHEN (old.status IS DISTINCT FROM new.status) EXECUTE PROCEDURE trig_test()\n\n",
